import { Component } from '@angular/core';

@Component({
  selector: 'app-equipamentos-categorias',
  templateUrl: './equipamentos-categorias.component.html',
  styleUrls: ['./equipamentos-categorias.component.css']
})
export class EquipamentosCategoriasComponent {

  categorias = [
    { nome: 'Ataque', link: '/equipamentos/ataque' },
    { nome: 'Defesa', link: '/equipamentos/defesa' },
    { nome: 'Utilitários', link: '/equipamentos/utilitarios' },
    { nome: 'Kits', link: '/equipamentos/kits' },
    { nome: 'Montaria', link: '/equipamentos/montaria' },
    { nome: 'Mágicos', link: '/equipamentos/magicos' }
  ];

}
